// isDaylightSavingTime makes a simple determination if a date is likely in DST
// US DST typically runs from second Sunday in March to first Sunday in November
func isDaylightSavingTime(t time.Time) bool {
	month := t.Month()
	// Simple heuristic: March through October are likely DST months for US
	// This isn't perfect but good enough for display purposes
	return month >= time.March && month <= time.October
}

